            signedXml.LoadXml((XmlElement)signatureNode[0]!);
            return signedXml.CheckSignature(_signingCertificate, true);
        }

        private static string SecurityElement(string input)
        {
            return input
                .Replace("&", "&amp;")
                .Replace("<", "&lt;")
                .Replace(">", "&gt;")
                .Replace("\"", "&quot;")
                .Replace("'", "&apos;");
        }

        private X509Certificate2 GenerateSelfSignedCertificate()
        {
            var request = new CertificateRequest(
                "CN=Enterprise SSO SAML Signing, O=Enterprise Corp, C=US",
                _rsaKey,
                HashAlgorithmName.SHA256,
                RSASignaturePadding.Pkcs1);

            request.CertificateExtensions.Add(
                new X509KeyUsageExtension(
                    X509KeyUsageFlags.DigitalSignature | X509KeyUsageFlags.KeyEncipherment,
                    critical: true));

            request.CertificateExtensions.Add(
                new X509BasicConstraintsExtension(false, false, 0, true));

            var certificate = request.CreateSelfSigned(
                DateTimeOffset.UtcNow.AddDays(-1),
                DateTimeOffset.UtcNow.AddYears(2));

            return certificate;
        }

